 1	import { FC, ReactNode, Suspense, useState } from 'react';
 2	
 3	import Connectors from '@pages/tabs/Connectors/Connectors';
 4	import Listeners from '@pages/tabs/Listeners/Listeners';
 5	import YAML from '@pages/tabs/YAML';
 6	import { PageSection, PageSectionVariants, PageNavigation, Bullseye, Spinner } from '@patternfly/react-core';
 7	
 8	import AlertStatus from './components/AlertStatus';
 9	import { TabNavigation } from './components/MenuTabs';
10	import Details from './tabs/Details/Details';
11	import GetStarted from './tabs/GetStarted';
12	import Links from './tabs/Links/Links';
13	
14	const SitePage: FC<{ siteId: string }> = function ({ siteId }) {
15	  const [activeTabKey, setActiveTabKey] = useState<string | number>(0);
16	
17	  const handleTabClick = (tabIndex: string | number) => {
18	    setActiveTabKey(tabIndex);
19	  };
20	
21	  const MenuTabs: ReactNode[] = [
22	    <GetStarted key={1} siteId={siteId || ''} />,
23	    <Details key={2} onGoTo={handleTabClick} />,
24	    <YAML key={3} />,
25	    <Links siteId={siteId || ''} key={4} />,
26	    <Listeners key={5} />,
27	    <Connectors key={6} />
28	  ];
29	
30	  return (
31	    <>
32	      <AlertStatus />
33	      <PageSection variant={PageSectionVariants.light} padding={{ default: 'noPadding' }} className="pf-v5-u-mx-md">
34	        <PageNavigation>
35	          <TabNavigation activeTabKey={activeTabKey} setActiveTabKey={setActiveTabKey} />
36	        </PageNavigation>
37	
38	        <Suspense
39	          fallback={
40	            <Bullseye>
41	              <Spinner size="xl" />
42	            </Bullseye>
43	          }
44	        >
45	          {MenuTabs[activeTabKey as number]}
46	        </Suspense>
47	      </PageSection>
48	    </>
49	  );
50	};
51	
52	export default SitePage;

